package be.schaubroeck.lpb.rkm.rekenmotor.factory;

import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst.DoeTussenkomst;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import com.google.common.collect.ImmutableSet;
import org.apache.commons.chain.Command;

import java.util.Set;

public class SociaalRekenenChainFactory extends NeutraliseerChainFactory {

    public SociaalRekenenChainFactory(ConstantManager constantManager, NlpGlobalService globalService) {
        super(constantManager, globalService);
    }

    public SociaalRekenenChainFactory(Admin admin, NlpGlobalService globalService) {
        super(admin, globalService);
    }

    @Override
    protected Command getManueleTussenkomstCommand(Set<MoneyKey> bedragTypes, RekenFase rekenFase) {
        if (rekenFase == RekenFase.SOCIAAL || rekenFase == RekenFase.BRUTO) {
            return new DoeTussenkomst(bedragTypes);
        } else {
            return new NeutraliseerChainFactory.NeutraliserendTussenkomstChain(globalService, bedragTypes);
        }
    }

    @Override
    protected Command getManueleTussenkomstPassiefCommand() {
        return new DoeTussenkomst();
    }

    private static final Set<RekenBedragType> TE_NEUTRALISEREN_REKENBEDRAGTYPES_SET =
            ImmutableSet.of(RekenBedragType.BELASTBAAR, RekenBedragType.BELASTBAAR_ACHTERSTAL, RekenBedragType.DIFF_BELASTBAAR_ACHTERSTAL, RekenBedragType.RUW_BELASTBAAR,
                    RekenBedragType.NIET_BELASTBAAR_APO, RekenBedragType.VRIJSTELLING_BELASTBAAR, RekenBedragType.BEDRIJFSVOORHEFFING,
                    RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL, RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_A,
                    RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_B,
                    RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_INHOUDINGEN, RekenBedragType.VLAAMSE_VERMINDERING_BEDRIJFSVOORHEFFING,
                    RekenBedragType.BIJDRAGE_WG_MTC, RekenBedragType.NETTO, RekenBedragType.NETTO_AFWIJKING
            );

    @Override
    protected Command getSleutelTussenkomstCommand() {
        return new NeutraliseerChainFactory.NeutraliserendSleutelTussenkomstChain(TE_NEUTRALISEREN_REKENBEDRAGTYPES_SET);
    }

}
